css:
/* setting the h1 color depending on the theme */
.fd-form h1, .fd-form .h1 {
    color: var(--fd-primary) !important;
}

/* setting the background of the InkSketch control */
.fd-form .fd-signature.accident .fd-signature-canvas   {
    box-sizing: border-box;
    background: url(https://plumsail.com/assets/forms/templates/vehicle-accident-report-form-image-01.jpg) no-repeat;
    background-size: cover;
}
